import{_ as t,C as n,o as l,c as s,E as a,w as r,a as o,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Poland Legal Rights","description":"Legal rights for transgender people in Poland","frontmatter":{"layout":"doc","title":"Poland Legal Rights","description":"Legal rights for transgender people in Poland"},"headers":[],"relativePath":"europe/poland/legal-rights.md","filePath":"europe/poland/legal-rights.md","lastUpdated":null}'),c={name:"europe/poland/legal-rights.md"};function g(u,e,h,p,m,f){const i=n("Badge");return l(),s("div",null,[a(i,{variant:"red"},{default:r(()=>[...e[0]||(e[0]=[o("No Clear Legal Framework",-1)])]),_:1}),a(i,{variant:"yellow"},{default:r(()=>[...e[1]||(e[1]=[o("Court Decisions Vary by Region",-1)])]),_:1}),a(i,{variant:"red"},{default:r(()=>[...e[2]||(e[2]=[o("Government Appeals Cases",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="legal-rights-in-poland" tabindex="-1">Legal Rights in Poland <a class="header-anchor" href="#legal-rights-in-poland" aria-label="Permalink to &quot;Legal Rights in Poland&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Poland has <strong>no comprehensive gender recognition law</strong> — the process relies on civil court decisions that vary dramatically by region:</p><ul><li><strong>Requirements</strong>: Medical diagnosis of gender dysphoria required</li><li><strong>Process</strong>: File a lawsuit against parents for &quot;rectification of civil status&quot;</li><li><strong>Surgery</strong>: Not explicitly required by law, but some judges demand it</li><li><strong>Government appeals</strong>: The government frequently appeals positive rulings, prolonging the process</li><li><strong>Age</strong>: 18+ only</li><li><strong>Regional variation</strong>: Courts in Warsaw and Kraków are more likely to approve; courts in smaller, conservative towns often reject</li></ul><h3 id="the-process" tabindex="-1">The Process <a class="header-anchor" href="#the-process" aria-label="Permalink to &quot;The Process&quot;">​</a></h3><ol><li>Diagnosis from a sexuologist or psychiatrist</li><li>Minimum period of documented HRT and real-life experience</li><li>File a civil lawsuit against parents to change gender marker</li><li>Attend court hearings (typically 2-4 over 6-18 months)</li><li>If approved, update civil registry and obtain new documents</li></ol><p><strong>Note</strong>: The European Court of Human Rights ruled in 2024 that Poland violates human rights by failing to provide clear legal gender recognition procedures. The process remains humiliating, expensive, and uncertain.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><ul><li>Processed through the <strong>Civil Registry Office</strong> (Urząd Stanu Cywilnego)</li><li>Name change can be done before or separately from gender marker change</li><li>Requires a valid reason</li><li>Processed within 1-2 months typically</li><li>Some registrars may refuse — appeals are possible</li></ul><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><ul><li><strong>Employment</strong>: Prohibited under the Labour Code for sexual orientation, but gender identity is not explicitly mentioned</li><li><strong>Goods and Services</strong>: General protections under the Act on Implementation of Certain EU Regulations</li><li><strong>Enforcement</strong>: The Commissioner for Human Rights (Rzecznik Praw Obywatelskich) handles complaints</li><li>Practical enforcement is weak, especially outside major cities</li></ul><h3 id="lgbtq-free-zones" tabindex="-1">&quot;LGBTQ+ Free Zones&quot; <a class="header-anchor" href="#lgbtq-free-zones" aria-label="Permalink to &quot;&quot;LGBTQ+ Free Zones&quot;&quot;">​</a></h3><ul><li>Over 100 municipalities have adopted resolutions declaring themselves &quot;free from LGBTQ+ ideology&quot;</li><li>These are symbolic but signal social hostility</li><li>Some municipalities have rescinded these resolutions after EU funding pressure</li></ul><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><ul><li>The <strong>Criminal Code</strong> includes hate crime provisions for race, religion, nationality</li><li>Sexual orientation is included, but enforcement is inconsistent</li><li>Gender identity is <strong>not explicitly mentioned</strong></li><li>Far-right groups are active and attacks on LGBTQ+ people occur</li><li>Police response varies significantly by region</li></ul><h2 id="document-recognition" tabindex="-1">Document Recognition <a class="header-anchor" href="#document-recognition" aria-label="Permalink to &quot;Document Recognition&quot;">​</a></h2><ul><li>Updated passports and ID cards are recognized internationally</li><li>Previous documents are archived but not publicly accessible</li><li>People with changed documents may still face issues with certain databases remaining unchanged</li><li>The gender marker mismatch between documents and presentation can cause problems</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://transfuzja.org/" target="_blank" rel="noreferrer">Trans-Fuzja Foundation</a></li><li><a href="https://kph.org.pl/" target="_blank" rel="noreferrer">KPH (Campaign Against Homophobia)</a></li><li><a href="https://www.rpo.gov.pl/" target="_blank" rel="noreferrer">Commissioner for Human Rights (RPO)</a></li><li><a href="https://www.ilga-europe.org/country/poland/" target="_blank" rel="noreferrer">ILGA-Europe - Poland</a></li></ul>',19))])}const v=t(c,[["render",g]]);export{y as __pageData,v as default};
